<script setup lang="ts">import {computed, nextTick, onMounted, reactive, ref} from "vue";// 编辑器相关const item = reactive({  id: -1,  originContent: '我是编辑器内容',  currentContent: '我是编辑器内容',})const textarea = ref<any>(null);const lineNumbers = ref<any>(null);const currentLine = ref<number>(1);// 计算行数const lineCount = computed(() => {  if (!item.currentContent) return 1  return item.currentContent.split('\n').length})/** * 更新当前行号 */const updateCurrentLine = (): void => {  if (!textarea.value) return  const cursorPos = textarea.value.selectionStart  const textBeforeCursor = item.currentContent.substring(0, cursorPos)  currentLine.value = textBeforeCursor.split('\n').length}/** * 更新行数显示 */const updateLineCount = (): void => {  updateCurrentLine()  nextTick(() => {    syncScroll()  })}/** * 同步滚动 */const syncScroll = (): void => {  if (lineNumbers.value && textarea.value) {    lineNumbers.value.scrollTop = textarea.value.scrollTop  }}/** * 处理键盘事件（如Tab键插入4个空格） * @param e */const handleKeydown = (e: any): void => {  if (e.key === 'Tab') {    e.preventDefault()    const start = e.target.selectionStart    const end = e.target.selectionEnd    // 在光标位置插入4个空格    item.currentContent = item.currentContent.substring(0, start) + '    ' + item.currentContent.substring(end)    // 移动光标到插入内容后    nextTick(() => {      e.target.selectionStart = e.target.selectionEnd = start + 4      updateCurrentLine()    })  } else if (e.key === 'Enter') {    // 处理回车键时保持缩进    setTimeout(() => {      updateCurrentLine()    }, 0)  }}/** * 点击textarea时更新当前行号 */const onClickTextarea = (): void => {  setTimeout(() => {    updateCurrentLine()  }, 0)}onMounted(() => {  // 初始化行数  updateLineCount();  // 监听textarea的input事件  if (textarea.value) {    textarea.value.addEventListener('input', updateCurrentLine)  }})</script><template>  <n-collapse-item class="custom-theme-collapse-item" title="文本编辑器组件" name="3">    <div class="text-editor">      <div class="editor-container">        <div class="line-numbers" ref="lineNumbers">          <div              v-for="line in lineCount"              :key="line"              class="line-number"              :class="{ 'active-line': line === currentLine }"          >            {{ line }}          </div>        </div>        <textarea            ref="textarea"            v-model="item.currentContent"            class="editor-textarea"            @scroll="syncScroll"            @input="updateLineCount"            @keydown="handleKeydown"            @click="onClickTextarea"            spellcheck="false"        />      </div>    </div>  </n-collapse-item></template><style scoped>/* 编辑器样式 start */.text-editor {  width: 100%;  height: 100%;  background-color: var(--preview-editor-backgroundColor);}.editor-container {  display: flex;  border: 1px solid var(--preview-universal-border);  overflow: hidden;  height: 300px;}.line-numbers {  background-color: var(--preview-editor-lineNumberBackgroundColor);  padding: 10px 0;  text-align: right;  overflow: hidden;  user-select: none;  border-right: 1px solid var(--preview-universal-border);  font-size: 14px;  line-height: 1.5;}.line-number {  padding: 0 8px;  color: var(--preview-universal-textHint);  height: 21px; /* 匹配textarea行高 */}.line-number.active-line {  background-color: var(--preview-editor-lineNumberBackgroundColorActive);  color: var(--preview-universal-text);}.editor-textarea {  flex: 1;  margin: 10px 0;  border: none;  resize: none;  font-size: 14px;  line-height: 1.5;  font-family: inherit;  outline: none;  overflow: auto;  background-color: var(--preview-editor-backgroundColor);  color: var(--preview-universal-text);}.editor-textarea:focus {  box-shadow: none;}/* 编辑器样式 end */</style>